#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#define EPS 1e-8
#define PI 3.14159265358979323846

// Structure to represent a point
typedef struct {
    double x, y;
} Point;

// Function to calculate the cross product of two vectors
double crossProduct(Point p1, Point p2, Point p3) {
    return (p2.x - p1.x) * (p3.y - p1.y) - (p2.y - p1.y) * (p3.x - p1.x);
}

// Function to calculate the winding number of a point with respect to a polygon
int windingNumber(Point p, Point *polygon, int n) {
    int wn = 0;
    for (int i = 0; i < n; i++) {
        if (polygon[i].y <= p.y) {
            if (polygon[(i + 1) % n].y > p.y && crossProduct(polygon[i], polygon[(i + 1) % n], p) > 0) {
                wn++;
            }
        } else {
            if (polygon[(i + 1) % n].y <= p.y && crossProduct(polygon[i], polygon[(i + 1) % n], p) < 0) {
                wn--;
            }
        }
    }
    return wn;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        Point nails[N];
        for (int i = 0; i < N; i++) {
            scanf("%lf %lf", &nails[i].x, &nails[i].y);
        }
        int M;
        scanf("%d", &M);
        Point rubberBand[M];
        for (int i = 0; i < M; i++) {
            scanf("%lf %lf", &rubberBand[i].x, &rubberBand[i].y);
        }
        int canRemove = 1;
        for (int i = 0; i < N; i++) {
            if (windingNumber(nails[i], rubberBand, M) != 0) {
                canRemove = 0;
                break;
            }
        }
        if (canRemove) {
            printf("YES\n");
        } else {
            printf("NO\n");
        }
    }
    return 0;
}

